package main

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

func main() {
	// Set environment variables for development
	os.Setenv("GOPRIVATE", "*")
	os.Setenv("GOSUMDB", "off")
	
	// Get the current directory
	currentDir, err := os.Getwd()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error getting current directory: %v\n", err)
		os.Exit(1)
	}
	
	// Create a temporary directory for the go mod init
	tempDir, err := os.MkdirTemp("", "go-dep-setup")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error creating temp directory: %v\n", err)
		os.Exit(1)
	}
	defer os.RemoveAll(tempDir)
	
	// Initialize go module in temp directory
	cmd := exec.Command("go", "mod", "init", "temp")
	cmd.Dir = tempDir
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		fmt.Fprintf(os.Stderr, "Error initializing go module: %v\n", err)
		os.Exit(1)
	}
	
	// Read go.mod file to get dependencies
	goModPath := filepath.Join(currentDir, "go.mod")
	goModContent, err := os.ReadFile(goModPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error reading go.mod: %v\n", err)
		os.Exit(1)
	}
	
	// Parse dependencies from go.mod
	dependencies := parseDependencies(string(goModContent))
	
	// Install dependencies with insecure flag for internal repos
	for _, dep := range dependencies {
		if strings.Contains(dep, "internal") || strings.Contains(dep, "corp") {
			// Use insecure flag for internal repositories
			cmd := exec.Command("go", "get", "-insecure", dep)
			cmd.Dir = tempDir
			cmd.Stdout = os.Stdout
			cmd.Stderr = os.Stderr
			if err := cmd.Run(); err != nil {
				fmt.Fprintf(os.Stderr, "Error installing dependency %s: %v\n", dep, err)
				continue
			}
		} else {
			// Use regular go get for external dependencies
			cmd := exec.Command("go", "get", dep)
			cmd.Dir = tempDir
			cmd.Stdout = os.Stdout
			cmd.Stderr = os.Stderr
			if err := cmd.Run(); err != nil {
				fmt.Fprintf(os.Stderr, "Error installing dependency %s: %v\n", dep, err)
				continue
			}
		}
	}
	
	fmt.Println("Dependencies installed successfully")
}

func parseDependencies(content string) []string {
	var deps []string
	lines := strings.Split(content, "\n")
	
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, "require") {
			continue
		}
		if strings.HasPrefix(line, "replace") {
			continue
		}
		if strings.HasPrefix(line, "//") {
			continue
		}
		if line == "" {
			continue
		}
		
		// Extract package name from dependency line
		parts := strings.Fields(line)
		if len(parts) >= 1 {
			dep := parts[0]
			// Skip version suffixes
			if strings.Contains(dep, "@") {
				dep = strings.Split(dep, "@")[0]
			}
			deps = append(deps, dep)
		}
	}
	
	return deps
}